		assert.strictEqual(getCell(ws.getRange2(FORMULA_COL + curRow)).getFormulaParsed().getArrayFormulaRef().getName(), "K58:K59", "spill range (B63:B64): FV(A2:A3,C2:C3,D2:D3)");
